import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

export default function FigmaRegister() {
    const [username, setUsername] = useState('');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [password2, setPassword2] = useState('');
    const { register } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (password !== password2) { alert('Пароли не совпадают'); return; }
        const success = await register({ username, email, password, password2 });
        if (success) navigate('/login');
    };

    return (
        <div className="input_form-214">
            <div className="logo-203"><div className="rectangle-982-204"></div></div>
            <form onSubmit={handleSubmit}>
                <div className="property-1-default" style={{ marginBottom: '15px' }}>
                    <input type="text" placeholder="Имя пользователя" value={username} onChange={e => setUsername(e.target.value)} style={{ background: 'transparent', border: 'none', color: 'white', flex: 1, outline: 'none' }} required />
                </div>
                <div className="property-1-default" style={{ marginBottom: '15px' }}>
                    <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} style={{ background: 'transparent', border: 'none', color: 'white', flex: 1, outline: 'none' }} required />
                </div>
                <div className="property-1-default" style={{ marginBottom: '15px' }}>
                    <input type="password" placeholder="Пароль" value={password} onChange={e => setPassword(e.target.value)} style={{ background: 'transparent', border: 'none', color: 'white', flex: 1, outline: 'none' }} required />
                </div>
                <div className="property-1-default" style={{ marginBottom: '25px' }}>
                    <input type="password" placeholder="Подтвердите пароль" value={password2} onChange={e => setPassword2(e.target.value)} style={{ background: 'transparent', border: 'none', color: 'white', flex: 1, outline: 'none' }} required />
                </div>
                <div className="property-1-default" onClick={handleSubmit}><p className="text-224">Зарегистрироваться</p></div>
            </form>
            <p style={{ textAlign: 'center', marginTop: '20px', color: '#999' }}>Уже есть аккаунт? <Link to="/login" style={{ color: '#8B5CF6' }}>Войти</Link></p>
        </div>
    );
}
